  ('aboriginal-7fec267e-moex-00235', 'aboriginal-7fec267e', 'aboriginal-7fec267e-moex-112-3082b5f1', 'sub-aboriginal-7fec267e-04', NULL, 'single_choice', '關於行政救濟之敘述，下列何者錯誤？', '["撤銷訴訟進行中，因原處分已執行完畢，如原告仍有受確認判決之法律上利益時，原告仍可將 撤銷訴訟變更確認處分違法之訴訟", "行政機關就其行政處分之作成，依法雖有裁量權，但其裁量權有濫用權力之情形，行政法院仍 可撤銷該行政處分", "除法律有特別規定外，撤銷訴訟須先經訴願程序始得合法提起", "人民起訴請求行政機關給付金錢之行政訴訟，應先經訴願程序，始得為之"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:01+00:00", "source_pdf_sha1": "0742f2f54d5c", "answer_pdf_sha1": "107658906250", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "501", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "一般行政"}'::jsonb, NULL),
